$$
 a^m \cdot a^n &= \underbrace{(a \cdot a \cdots a)}_{m \text{ factors}} 
 \cdot \underbrace{(a \cdot a \cdots a)}_{n \text{ factors}} \\
 &= \underbrace{a \cdot a \cdots a}_{m + n \text{ factors}} = a^{m+n}
$$

\[
 (a^m)^n = \underbrace{a^m \cdot a^m \cdots a^m}_{n \text{ factors}}
 = a^{m + m + \cdots + m} = a^{mn}
\]
